conn = sqlite3.connect('database.db')
cur = conn.cursor()

for tbl in ['items_g1','items_g2','items_g3']:
    print('\nTABLE', tbl)
    for row in cur.execute(f"SELECT main_cat, COUNT(*) FROM {tbl} GROUP BY main_cat ORDER BY COUNT(*) DESC LIMIT 10"):
        print(row)
    print('sample:')
    for row in cur.execute(f"SELECT ref_id, ttl, main_cat FROM {tbl} LIMIT 5"):
        print(row)

for tbl in ['fdbk_g1','fdbk_g2','fdbk_g3']:
    print('\nFDBK', tbl)
    rows = cur.execute(f"SELECT ts FROM {tbl} LIMIT 5").fetchall()
    print('sample ts:', rows)
    vals = [r[0] for r in cur.execute(f"SELECT ts FROM {tbl} WHERE ts IS NOT NULL LIMIT 3")]
    for v in vals:
        try:
            if isinstance(v, int):
                for div in [1,1000]:
                    try:
                        print(v, div, datetime.datetime.utcfromtimestamp(v/div))
                    except Exception:
                        pass
            else:
                print(v)
        except Exception as e:
            print('err', e)
